async function execute(browser: WebFlowBrowserAPI, params: FlowParams): Promise<WebFlowResult> {
    const navLink = await browser.extractComponent<{ title: string; linkSelector: string }>(
        {
            typeName: 'NavigationLink',
            schema: '{ title: string; linkSelector: string; }'
        },
        params.categoryName || 'categories'
    );
    if (!navLink || !navLink.linkSelector) {
        throw new Error('Could not find category link' + (params.categoryName ? ' for: ' + params.categoryName : ''));
    }
    await browser.click(navLink.linkSelector);
    await browser.awaitPageLoad();
    return { success: true, message: 'Browsing ' + (navLink.title || params.categoryName || 'categories') };
}
